### Loom Tests

```rust
#[cfg(loom)]
mod loom_tests {
    use super::*;
    use loom::sync::atomic::{AtomicBool, AtomicU32, Ordering};
    use loom::thread;

    #[test]
    fn loom_parker_no_lost_wakeup() {
        loom::model(|| {
            let parker = Arc::new(Parker::new());
            let woken = Arc::new(AtomicBool::new(false));

            let p1 = parker.clone();
            let w1 = woken.clone();
            let h1 = thread::spawn(move || {
                p1.park();
                w1.store(true, Ordering::Release);
            });

            parker.unpark();
            h1.join().unwrap();

            assert!(woken.load(Ordering::Acquire), "Lost wakeup!");
        });
    }

    #[test]
    fn loom_parker_unpark_before_park() {
        loom::model(|| {
            let parker = Arc::new(Parker::new());

            // Unpark first
            parker.unpark();

            // Park should return immediately
            let p1 = parker.clone();
            let h1 = thread::spawn(move || {
                p1.park(); // Should not block
            });

            h1.join().unwrap();
        });
    }

    #[test]
    fn loom_wake_state_no_double_schedule() {
        loom::model(|| {
            let wake_state = Arc::new(AtomicU32::new(IDLE));
            let schedule_count = Arc::new(AtomicU32::new(0));

            let ws1 = wake_state.clone();
            let sc1 = schedule_count.clone();
            let h1 = thread::spawn(move || {
                let prev = ws1.swap(IDLE, Ordering::AcqRel);
                if prev == NOTIFIED {
                    sc1.fetch_add(1, Ordering::Relaxed);
                }
            });

            let ws2 = wake_state.clone();
            let sc2 = schedule_count.clone();
            thread::spawn(move || {
                let prev = ws2.swap(NOTIFIED, Ordering::AcqRel);
                if prev == IDLE {
                    sc2.fetch_add(1, Ordering::Relaxed);
                }
            }).join().unwrap();

            h1.join().unwrap();
            assert_eq!(schedule_count.load(Ordering::Relaxed), 1);
        });
    }

    #[test]
    fn loom_local_queue_steal_concurrent() {
        loom::model(|| {
            let queue = Arc::new(LocalQueue::new());

            // Producer pushes
            let q1 = queue.clone();
            let h1 = thread::spawn(move || {
                for i in 0..3 {
                    q1.push(Task::new(i));
                }
            });

            // Stealer steals
            let q2 = queue.clone();
            let stolen = Arc::new(AtomicU32::new(0));
            let s = stolen.clone();
            let h2 = thread::spawn(move || {
                while let Some(_) = q2.steal() {
                    s.fetch_add(1, Ordering::Relaxed);
                }
            });

            h1.join().unwrap();
            h2.join().unwrap();

            // All tasks either in queue or stolen
            let remaining = queue.len();
            let stolen_count = stolen.load(Ordering::Relaxed);
            assert_eq!(remaining + stolen_count, 3);
        });
    }

    #[test]
    fn loom_global_queue_mpsc() {
        loom::model(|| {
            let queue = Arc::new(GlobalQueue::new());

            let q1 = queue.clone();
            let h1 = thread::spawn(move || {
                q1.push(Task::new(1));
            });

            let q2 = queue.clone();
            let h2 = thread::spawn(move || {
                q2.push(Task::new(2));
            });

            h1.join().unwrap();
            h2.join().unwrap();

            // Both tasks present
            assert_eq!(queue.len(), 2);
        });
    }
}
```

### E2E Test Script

```bash
#!/bin/bash
# scripts/test_scheduler_wakeup_e2e.sh

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(dirname "$SCRIPT_DIR")"
LOG_DIR="$PROJECT_ROOT/test_logs/scheduler_$(date +%Y%m%d_%H%M%S)"
mkdir -p "$LOG_DIR"

echo "=== Scheduler Wakeup E2E Test Suite ==="
echo "Log directory: $LOG_DIR"
echo "Start time: $(date -Iseconds)"

# Run parker unit tests
echo ""
echo "[1/7] Running parker unit tests..."
RUST_LOG=debug cargo test --lib runtime::scheduler::parker -- --nocapture 2>&1 | tee "$LOG_DIR/parker_tests.log"
PARKER_EXIT=${PIPESTATUS[0]}

# Run wake state tests
echo ""
echo "[2/7] Running wake state unit tests..."
RUST_LOG=debug cargo test --lib runtime::scheduler::wake -- --nocapture 2>&1 | tee "$LOG_DIR/wake_tests.log"
WAKE_EXIT=${PIPESTATUS[0]}

# Run queue tests
echo ""
echo "[3/7] Running queue unit tests..."
RUST_LOG=debug cargo test --lib runtime::scheduler::queue -- --nocapture 2>&1 | tee "$LOG_DIR/queue_tests.log"
QUEUE_EXIT=${PIPESTATUS[0]}

# Run stealing tests
echo ""
echo "[4/7] Running work stealing tests..."
RUST_LOG=debug cargo test --lib runtime::scheduler::steal -- --nocapture 2>&1 | tee "$LOG_DIR/steal_tests.log"
STEAL_EXIT=${PIPESTATUS[0]}

# Run stress tests (with timeout)
echo ""
echo "[5/7] Running stress tests (timeout 180s)..."
timeout 180s cargo test --lib --release scheduler_stress -- --ignored --nocapture --test-threads=1 2>&1 | tee "$LOG_DIR/stress_tests.log"
STRESS_EXIT=${PIPESTATUS[0]}

# Run Loom tests
echo ""
echo "[6/7] Running Loom tests..."
if RUSTFLAGS="--cfg loom" cargo test --lib scheduler_loom -- --nocapture 2>&1 | tee "$LOG_DIR/loom_tests.log"; then
    LOOM_EXIT=0
else
    LOOM_EXIT=1
    echo "Loom tests failed"
fi

# Analyze for deadlock patterns
echo ""
echo "[7/7] Analyzing for issues..."
ISSUES=0
if grep -qE "(timed out|timeout|blocked|deadlock|hung)" "$LOG_DIR"/*.log 2>/dev/null; then
    echo "⚠️  WARNING: Potential deadlock/timeout detected"
    grep -hE "(timed out|timeout|blocked|deadlock|hung)" "$LOG_DIR"/*.log | head -10
    ISSUES=1
fi

if grep -qE "lost wakeup" "$LOG_DIR"/*.log 2>/dev/null; then
    echo "⚠️  WARNING: Lost wakeup detected"
    grep -h "lost wakeup" "$LOG_DIR"/*.log | head -10
    ISSUES=1
fi

if grep -qE "double schedule|duplicate" "$LOG_DIR"/*.log 2>/dev/null; then
    echo "⚠️  WARNING: Double scheduling detected"
    grep -hE "double schedule|duplicate" "$LOG_DIR"/*.log | head -10
    ISSUES=1
fi

# Generate summary
cat > "$LOG_DIR/summary.md" << EOF
# Scheduler Wakeup Test Report

## Date: $(date -Iseconds)

## Test Results

| Suite | Status |
|-------|--------|
| Parker | $([ $PARKER_EXIT -eq 0 ] && echo "✅ PASS" || echo "❌ FAIL") |
| Wake State | $([ $WAKE_EXIT -eq 0 ] && echo "✅ PASS" || echo "❌ FAIL") |
