| Stress | $([ $STRESS_EXIT -eq 0 ] && echo "✅ PASS" || echo "❌ FAIL") |
| Loom | $([ $LOOM_EXIT -eq 0 ] && echo "✅ PASS" || echo "❌ FAIL") |
| Analysis | $([ $ISSUES -eq 0 ] && echo "✅ CLEAN" || echo "⚠️ ISSUES") |

## Test Counts
$(grep -hE "^test result:" "$LOG_DIR"/*.log 2>/dev/null || echo "N/A")

## Failures
$(grep -hE "(FAILED|panicked)" "$LOG_DIR"/*.log 2>/dev/null | head -20 || echo "None")
EOF

echo ""
cat "$LOG_DIR/summary.md"

echo ""
echo "End time: $(date -Iseconds)"
echo "Logs saved to: $LOG_DIR"
echo "=== Test Complete ==="

# Exit with failure if any critical tests failed
[ $PARKER_EXIT -eq 0 ] && [ $WAKE_EXIT -eq 0 ] && [ $QUEUE_EXIT -eq 0 ] && [ $STRESS_EXIT -eq 0 ] && [ $LOOM_EXIT -eq 0 ] && [ $ISSUES -eq 0 ]
