 {"id":"bd-nz75","title":"SQLite async wrapper: blocking pool integration with Cx semantics","description":"# SQLite Async Wrapper Implementation

## Overview
Async wrapper around SQLite using the blocking pool with full Cx integration
and cancel-correct semantics.

## Background
SQLite is inherently synchronous (single file, no network protocol). We wrap
it with the blocking pool to provide async semantics while maintaining
correctness.

## Design

### Connection
```rust
pub struct SqliteConnection {
    inner: blocking::Handle<rusqlite::Connection>,
}

impl SqliteConnection {
    /// Open SQLite database.
    pub async fn open(cx: &Cx, path: &Path) -> Outcome<Self, SqliteError> {
        cx.checkpoint()?;

        let inner = blocking_pool::spawn(cx, move || {
            rusqlite::Connection::open(path)
        }).await?;

        Ok(Self { inner: blocking::Handle::new(inner) })
    }

    /// Open in-memory database.
    pub async fn open_in_memory(cx: &Cx) -> Outcome<Self, SqliteError> {
        cx.checkpoint()?;

        let inner = blocking_pool::spawn(cx, || {
            rusqlite::Connection::open_in_memory()
        }).await?;

        Ok(Self { inner: blocking::Handle::new(inner) })
    }
}
```

### Queries
```rust
impl SqliteConnection {
    /// Execute query.
    pub async fn query(&self, cx: &Cx, sql: &str) -> Outcome<Vec<Row>, SqliteError> {
        cx.checkpoint()?;

        self.inner.call(|conn| {
            let mut stmt = conn.prepare(sql)?;
            let columns = stmt.column_names().iter().map(|s| s.to_string()).collect();
            let rows = stmt.query_map([], |row| {
                // Map row to our Row type
                Ok(Row::from_rusqlite(row, &columns))
            })?.collect::<Result<Vec<_>, _>>()?;
            Ok(rows)
        }).await
    }

    /// Execute with parameters.
    pub async fn execute(
        &self,
        cx: &Cx,
        sql: &str,
        params: &[&dyn ToSql],
    ) -> Outcome<u64, SqliteError> {
        cx.checkpoint()?;

        self.inner.call(move |conn| {
            let affected = conn.execute(sql, rusqlite::params_from_iter(params))?;
            Ok(affected as u64)
        }).await
    }

    /// Execute batch of statements.
    pub async fn execute_batch(&self, cx: &Cx, sql: &str) -> Outcome<(), SqliteError> {
        cx.checkpoint()?;

        self.inner.call(|conn| {
            conn.execute_batch(sql)
        }).await
    }
}
```

### Transactions
```rust
impl SqliteConnection {
    /// Begin transaction.
    pub async fn begin(&self, cx: &Cx) -> Outcome<SqliteTransaction<'_>, SqliteError> {
        self.execute(cx, "BEGIN", &[]).await?;
        Ok(SqliteTransaction { conn: self, committed: false })
    }

    /// Begin immediate transaction (write lock).
    pub async fn begin_immediate(&self, cx: &Cx) -> Outcome<SqliteTransaction<'_>, SqliteError> {
        self.execute(cx, "BEGIN IMMEDIATE", &[]).await?;
        Ok(SqliteTransaction { conn: self, committed: false })
    }
}

pub struct SqliteTransaction<'a> {
    conn: &'a SqliteConnection,
    committed: bool,
}

impl<'a> SqliteTransaction<'a> {
    pub async fn commit(mut self, cx: &Cx) -> Outcome<(), SqliteError> {
        self.conn.execute(cx, "COMMIT", &[]).await?;
        self.committed = true;
        Ok(())
    }

    pub async fn rollback(mut self, cx: &Cx) -> Outcome<(), SqliteError> {
        self.conn.execute(cx, "ROLLBACK", &[]).await?;
        self.committed = true;
        Ok(())
    }
}
```

### Blocking Pool Handle
```rust
/// Handle for blocking operations on a single connection.
pub struct Handle<T> {
    inner: Arc<Mutex<T>>,
    pool: BlockingPool,
}

impl<T: Send + 'static> Handle<T> {
    /// Execute operation on the connection.
    pub async fn call<F, R>(&self, f: F) -> Outcome<R, SqliteError>
    where
        F: FnOnce(&mut T) -> Result<R, rusqlite::Error> + Send + 'static,
        R: Send + 'static,
    {
        let inner = Arc::clone(&self.inner);
        self.pool.spawn(move || {
            let mut guard = inner.lock().unwrap();
            f(&mut *guard)
        }).await
    }
}
```

