# scripts/bench_scheduler_e2e.sh

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(dirname "$SCRIPT_DIR")"
LOG_DIR="$PROJECT_ROOT/bench_logs/scheduler_$(date +%Y%m%d_%H%M%S)"
mkdir -p "$LOG_DIR"

echo "=== Scheduler Performance Benchmark Suite ==="
echo "Machine: $(uname -a)"
echo "CPUs: $(nproc)"
echo "Memory: $(free -h | grep Mem | awk '{print $2}')"
echo "Log directory: $LOG_DIR"
echo "Start: $(date -Iseconds)"

# Disable CPU frequency scaling for consistent results
if command -v cpupower &>/dev/null; then
    echo "Setting CPU governor to performance..."
    sudo cpupower frequency-set -g performance 2>/dev/null || echo "Could not set governor"
fi

# Warm up (compile and run once)
echo ""
echo "[0/6] Warming up..."
cargo bench --bench scheduler_micro -- --warm-up-time 5 >/dev/null 2>&1 || true

# Run micro-benchmarks
echo ""
echo "[1/6] Running micro-benchmarks..."
cargo bench --bench scheduler_micro 2>&1 | tee "$LOG_DIR/bench_micro.log"

# Run macro-benchmarks
echo ""
echo "[2/6] Running macro-benchmarks..."
cargo bench --bench scheduler_macro 2>&1 | tee "$LOG_DIR/bench_macro.log"

# Run comparison benchmarks
echo ""
echo "[3/6] Running comparison benchmarks..."
cargo bench --bench scheduler_compare 2>&1 | tee "$LOG_DIR/bench_compare.log" || echo "Comparison benchmarks skipped"

# Run scaling benchmarks
echo ""
echo "[4/6] Running scaling benchmarks..."
for workers in 1 2 4 8 $(nproc); do
    ASUPERSYNC_WORKERS=$workers cargo bench --bench scheduler_scale 2>&1 | tee -a "$LOG_DIR/bench_scale.log"
done

# Run regression tests
echo ""
echo "[5/6] Running regression tests..."
cargo test --release regression_ -- --nocapture 2>&1 | tee "$LOG_DIR/regression.log"
REGRESSION_EXIT=${PIPESTATUS[0]}

# Generate report
echo ""
echo "[6/6] Generating report..."

# Extract key metrics
THROUGHPUT=$(grep -oP 'throughput.*?(\d+(?:,\d+)*)\s*ops' "$LOG_DIR/bench_macro.log" | head -1 || echo "N/A")
P99_LATENCY=$(grep -oP 'p99.*?(\d+(?:\.\d+)?)\s*(us|ns|ms)' "$LOG_DIR/bench_macro.log" | head -1 || echo "N/A")

cat > "$LOG_DIR/report.md" << EOF
# Scheduler Benchmark Report

## Date
$(date -Iseconds)

## System
- Machine: $(uname -n)
- Kernel: $(uname -r)
- CPUs: $(nproc)
- Memory: $(free -h | grep Mem | awk '{print $2}')
- Rust: $(rustc --version)

## Summary

| Metric | Value |
|--------|-------|
| Throughput | $THROUGHPUT |
| P99 Latency | $P99_LATENCY |
| Regression Tests | $([ $REGRESSION_EXIT -eq 0 ] && echo "✅ PASS" || echo "❌ FAIL") |

## Micro-benchmark Results

\`\`\`
$(grep -E "^(test|bench)" "$LOG_DIR/bench_micro.log" | head -30)
\`\`\`

## Scaling Results

\`\`\`
$(grep -E "workers|throughput" "$LOG_DIR/bench_scale.log" | head -20)
\`\`\`

## Comparison vs Tokio

\`\`\`
$(grep -E "tokio|asupersync|ratio" "$LOG_DIR/bench_compare.log" | head -10)
\`\`\`

## Criterion Reports

HTML reports available at: target/criterion/

EOF

echo "=== Report Generated ==="
cat "$LOG_DIR/report.md"

echo ""
echo "End: $(date -Iseconds)"
echo "Logs saved to: $LOG_DIR"
echo "=== Benchmark Complete ==="

# Exit with failure if regression tests failed
exit $REGRESSION_EXIT
```

