```rust
// Run on every PR to catch regression
#[test]
fn regression_throughput_baseline() {
    warm_up();
    let ops = measure_throughput_10k_empty();
    let baseline = BASELINE_THROUGHPUT;
    let threshold = baseline * 0.9; // Allow 10% regression

    assert!(ops >= threshold,
        "Throughput regression: {} ops/sec < {} (baseline {} * 0.9)\n\
         This PR reduces throughput by {:.1}%",
        ops, threshold, baseline,
        (1.0 - ops as f64 / baseline as f64) * 100.0
    );
}

#[test]
fn regression_latency_p99() {
    warm_up();
    let p99 = measure_p99_latency_us();
    let baseline = BASELINE_P99_LATENCY_US;
    let threshold = baseline * 1.2; // Allow 20% regression

    assert!(p99 <= threshold,
        "P99 latency regression: {}us > {} (baseline {} * 1.2)\n\
         This PR increases p99 latency by {:.1}%",
        p99, threshold, baseline,
        (p99 as f64 / baseline as f64 - 1.0) * 100.0
    );
}

#[test]
fn regression_memory_per_task() {
    let bytes = measure_memory_per_task();
    let baseline = BASELINE_MEMORY_PER_TASK;
    let threshold = baseline * 1.1; // Allow 10% increase

    assert!(bytes <= threshold,
        "Memory regression: {} bytes/task > {} (baseline {} * 1.1)",
        bytes, threshold, baseline
    );
}
